import React, {useState} from 'react';
import api from '../services/api';

export default function Signup(){
  const [form, setForm] = useState({username:'',password:'',fullName:'',email:''});
  const [msg, setMsg] = useState(null);

  const onChange = e => setForm({...form, [e.target.name]: e.target.value});
  const onSubmit = async e => {
    e.preventDefault();
    try{
      const res = await api.post('/auth/register', form);
      setMsg({type:'success', text: res.data.message});
      setForm({username:'',password:'',fullName:'',email:''});
    }catch(err){
      const text = err?.response?.data?.error || 'Registration failed';
      setMsg({type:'error', text});
    }
  };

  return (
    <div style={{maxWidth:480}}>
      <h2>Sign Up</h2>
      {msg && <div style={{padding:8,background: msg.type==='success'?'#dfd':'#fdd'}}>{msg.text}</div>}
      <form onSubmit={onSubmit} style={{display:'grid',gap:8}}>
        <input name="fullName" placeholder="Full name" value={form.fullName} onChange={onChange} />
        <input name="email" placeholder="Email" value={form.email} onChange={onChange} />
        <input name="username" placeholder="Username" value={form.username} onChange={onChange} required />
        <input name="password" type="password" placeholder="Password" value={form.password} onChange={onChange} required />
        <button type="submit">Register</button>
      </form>
    </div>
  )
}
